import React from 'react';
import { CircleCheck, Bug, Stopwatch, ShieldHalved } from 'lucide-react';
import KPICard from '../ui/KPICard';

const PulseSection = ({ showInsights }) => {
  return (
    <section id="section-pulse" className="mb-10">
      <div className="flex items-center gap-2 mb-4">
        <h3 className="text-lg font-bold text-slate-700 uppercase tracking-wide">1. The Pulse (핵심 지표)</h3>
        <div className="h-px flex-1 bg-slate-200"></div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <KPICard 
          title="Pass Rate (통과율)"
          value="85.0%"
          subValue="↑ 13.0%"
          subText="vs 1차 (72%)"
          icon={CircleCheck}
          colorClass="bg-emerald-50 text-emerald-600"
          insight="1차(72%) 대비 많이 개선되었습니다. 하지만 아직 목표치 98%까지 갈 길이 멉니다."
          showInsights={showInsights}
        />
        <KPICard 
          title="Critical Bugs"
          value="2"
          subValue="Action Required"
          subText=""
          icon={Bug}
          colorClass="bg-red-50 text-red-600"
          highlight={true}
          insight="이 숫자가 0이 아니면 절대 출시 불가입니다. 진척률이 99%라도 의미 없습니다. Red Light!"
          showInsights={showInsights}
        />
        <KPICard 
          title="Avg. Fix Time"
          value="4.2h"
          subValue="Good"
          subText="Velocity Status"
          icon={Stopwatch}
          colorClass="bg-blue-50 text-blue-600"
          insight="개발팀의 속도입니다. 이 시간이 늘어나면 병목이 생겼거나 난이도가 높아진 것입니다."
          showInsights={showInsights}
        />
        <KPICard 
          title="Test Coverage"
          value="92%"
          subValue="Stable"
          subText="vs Target 90%"
          icon={ShieldHalved}
          colorClass="bg-purple-50 text-purple-600"
          insight="우리가 놓치고 있는 영역이 없는지 확인합니다. 목표치 90%를 넘겨 안정적입니다."
          showInsights={showInsights}
        />
      </div>
    </section>
  );
};

export default PulseSection;
